INSERT INTO exercise_body_target (exercise_slug, body_target_slug) 
INSERT INTO exercises_info (slug, lang, title, description, benefits, instructions, tips, restrictions, mistakes) VALUES
('crunch', 'es', 'Crunch abdominal', 'El crunch abdominal es el ejercicio de referencia para el aislamiento de la pared abdominal anterior. Al focalizarse en la flexión segmentada de la columna torácica, permite trabajar el recto abdominal con mínima intervención de los flexores de la cadera.', 'Aumenta la fuerza y resistencia del recto abdominal.\nOptimiza el control neuromuscular de la columna torácica.\nMejora la transferencia de fuerzas a través del tronco.\nPermite un entrenamiento de alta precisión sin cargas externas.', 'Túmbate en decúbito supino con rodillas flexionadas a 90 grados y pies apoyados en el suelo.\nSitúa las manos suavemente tras la nuca, evitando entrelazar los dedos.\nRealiza una flexión controlada de la columna torácica, despegando únicamente las escápulas del suelo.\nDesciende de forma lenta y pausada, manteniendo siempre la tensión en el abdomen.', 'Visualiza que intentas aproximar el esternón al pubis en lugar de elevar el torso.\nMantén una distancia constante entre la barbilla y el pecho para proteger la zona cervical.\nRealiza una exhalación forzada en el punto de máxima contracción.', 'Evitar en fases agudas de hernia discal cervical o torácica.\nPersonas con hipercifosis deben consultar con un especialista para ajustar el rango de movimiento.\nNo realizar tras cirugías abdominales recientes sin autorización médica.', 'Utilizar los brazos como palanca para traccionar del cuello.\nElevar la zona lumbar del suelo, involucrando los flexores de la cadera.\nEjecutar el movimiento a gran velocidad, desperdiciando la fase excéntrica.'),
('crunch', 'en', 'Crunch', 'The abdominal crunch is the gold standard for isolating the anterior abdominal wall. By emphasizing segmental thoracic spine flexion, it engages the rectus abdominis while minimizing hip flexor recruitment.', 'Increases strength and endurance of the rectus abdominis.\nOptimizes neuromuscular control of the thoracic spine.\nImproves power transfer efficiency through the torso.\nAllows for high-precision training without external resistance.', 'Lie in a supine position with knees bent at 90 degrees and feet flat.\nPlace hands lightly behind the neck, avoiding pulling.\nPerform a controlled flexion of the thoracic spine, lifting only the shoulder blades.\nLower gradually, maintaining constant abdominal tension.', 'Visualize bringing the sternum toward the pubis rather than lifting the whole torso.\nMaintain a constant gap between chin and chest to safeguard the cervical spine.\nExhale forcefully at the peak of the contraction.', 'Avoid during acute stages of cervical or thoracic disc herniations.\nIndividuals with hyperkyphosis should seek professional advice to adjust the range of motion.\nDo not perform following recent abdominal surgery without medical clearance.', 'Using arms to pull on the neck, causing unnecessary cervical strain.\nLifting the lumbar region, which engages hip flexors.\nPerforming the movement too quickly, wasting the eccentric phase.'),
('crunch', 'pt', 'Crunch abdominal', 'O crunch abdominal é o movimento básico para o isolamento da parede abdominal anterior. Ao enfatizar a flexão segmentada da coluna torácica, permite trabalhar o reto abdominal com mínima intervenção dos flexores do quadril.', 'Aumenta a força e a resistência do reto abdominal.\nOtimiza o controle neuromuscular da coluna torácica.\nMelhora a transferência de força eficiente através do tronco.\nPermite um treinamento de alta precisão sem necessidade de cargas externas.', 'Deite-se em decúbito supino com joelhos flexionados a 90 graus e pés apoiados no chão.\nColoque as mãos levemente atrás da nuca, evitando entrelaçar os dedos.\nRealize uma flexão controlada da coluna torácica, desencostando apenas as escápulas do chão.\nDesça de forma lenta, mantendo a tensão abdominal constante.', 'Visualize que tenta aproximar o esterno do púbis em vez de elevar o tronco inteiro.\nMantenha uma distância constante entre o queixo e o peito para proteger a região cervical.\nRealize uma exalação forçada no ponto de máxima contração.', 'Evitar em fases agudas de hérnia discal cervical ou torácica.\nPessoas com hipercifose devem consultar um especialista para ajustar o alcance do movimento.\nNão realizar após cirurgias abdominais recentes sem autorização médica.', 'Utilizar os braços como alavanca para tracionar o pescoço.\nElevar a região lombar do chão, envolvendo os flexores do quadril.\nExecutar o movimento em alta velocidade, desperdiçando a fase excêntrica.'),
('crunch', 'fr', 'Crunch', 'Le crunch abdominal est le mouvement de référence pour l''isolation de la paroi abdominale antérieure. En mettant l''accent sur la flexion segmentaire de la colonne thoracique, il permet de solliciter le grand droit tout en minimisant l''intervention des fléchisseurs de la hanche.', 'Augmente la force et l''endurance du grand droit.\nOptimise le contrôle neuromusculaire de la colonne thoracique.\nAméliore l''efficacité du transfert de force à travers le tronc.\nPermet un entraînement de haute précision sans charges externes.', 'Allongez-vous en décubitus dorsal, genoux fléchis à 90 degrés et pieds au sol.\nPlacez les mains légèrement derrière la nuque, sans tirer.\nRéalisez une flexion contrôlée de la colonne thoracique, en décollant uniquement les omoplates.\nRedescendez lentement, en maintenant une tension abdominale constante.', 'Visualisez le rapprochement du sternum vers le pubis plutôt que l''élévation du buste.\nGardez une distance constante entre le menton et la poitrine.\nExpirez intensément au pic de la contraction.', 'À éviter en cas de hernie discale cervicale ou thoracique aiguë.\nLes personnes hypercyphosiques doivent adapter l''amplitude du mouvement.\nInterdit après une chirurgie abdominale récente sans avis médical.', 'Utiliser les bras pour tirer sur la nuque, causant des tensions cervicales.\nDécoller les lombaires, ce qui engage les fléchisseurs de la hanche.\nEffectuer le mouvement trop rapidement, négligeant la phase excentrique.'),
('crunch', 'de', 'Crunches', 'Der abdominale Crunch ist eine klassische Rumpf-Stärkungsübung, die den geraden Bauchmuskel isoliert. Durch die segmentierte Flexion der Brustwirbelsäule wird der Rectus abdominis effektiv angesprochen, während die Hüftbeuger weitgehend inaktiv bleiben.', 'Stärkt den geraden Bauchmuskel und erhöht die Rumpfkraft.\nOptimiert die neuromuskuläre Kontrolle der Brustwirbelsäule.\nVerbessert die Kraftübertragung durch den Rumpf.\nErmöglicht präzises Training ohne externe Gewichte.', 'Legen Sie sich mit angewinkelten Knien (90°) auf den Rücken.\nLegen Sie die Hände locker in den Nacken, ohne zu ziehen.\nBeugen Sie kontrolliert nur die Brustwirbelsäule und heben Sie nur die Schulterblätter ab.\nSenken Sie den Oberkörper langsam unter konstanter Bauchspannung ab.', 'Denken Sie daran, das Brustbein Richtung Schambein zu ziehen, statt nur den Oberkörper anzuheben.\nHalten Sie das Kinn leicht vom Brustbein entfernt.\nAtmen Sie bei der Kontraktion kräftig aus.', 'Bei akuten Bandscheibenvorfällen im HWS- oder BWS-Bereich vermeiden.\nPersonen mit Hyperkyphose sollten den Bewegungsumfang anpassen.\nNicht ohne ärztliche Freigabe nach kürzlichen Bauch-OPs ausführen.', 'Den Nacken mit den Armen nach vorne ziehen.\nDen unteren Rücken abheben und damit die Hüftbeuger aktivieren.\nDie Bewegung zu schnell ausführen und die exzentrische Phase vernachlässigen.'),
('crunch', 'it', 'Crunch addominale', 'Il crunch addominale è l''esercizio fondamentale per isolare la parete addominale anteriore. Enfasi sulla flessione segmentata della colonna toracica per ingaggiare il retto addominale riducendo l''intervento dei flessori dell''anca.', 'Aumenta la forza e la resistenza del retto addominale.\nOttimizza il controllo neuromuscolare della colonna toracica.\nMigliora l''efficienza del trasferimento di forza attraverso il tronco.\nPermette un allenamento ad alta precisione.', 'Sdraiati in decubito supino con ginocchia flesse a 90 gradi e piedi a terra.\nPosiziona le mani leggermente dietro la nuca senza intrecciare le dita.\nFletti in modo controllato la colonna toracica, staccando solo le scapole dal suolo.\nScendi lentamente mantenendo la tensione addominale costante.', 'Visualizza di avvicinare lo sterno al pube invece di sollevare tutto il busto.\nMantieni una distanza costante tra mento e petto per proteggere il collo.\nEspira con forza nel punto di massima contrazione.', 'Evitare in fasi acute di ernia discale cervicale o toracica.\nLe persone con ipercifosi devono consultare uno specialista per regolare il raggio di movimento.\nNon eseguire dopo recenti interventi chirurgici addominali.', 'Usare le braccia per tirare il collo, creando tensioni inutili.\nSollevare la zona lombare, coinvolgendo eccessivamente i flessori dell''anca.\nEseguire il movimento a velocità eccessiva senza controllo.'),
('crunch', 'zh', '腹部卷腹', '腹部卷腹是针对腹壁前侧的经典隔离训练。通过胸椎的节段性屈曲，能有效激活腹直肌并最小化髋屈肌的参与，是核心控制的基石。', '增强腹直肌的力量和耐力。\n优化胸椎的神经肌肉控制能力。\n提高躯干力量传导的效率。\n在无需外加阻力的情况下实现高精度训练。', '仰卧，膝盖弯曲至90度，双脚平放于地面。\n双手轻置于后颈部，避免手指交叉拉扯。\n受控地屈曲胸椎，仅使肩胛骨离地。\n缓慢下落，并在全程保持腹部紧张。', '想象胸骨向耻骨靠近，而非简单地抬起上半身。\n保持下巴与胸部之间的间距以保护颈椎。\n在收缩顶点进行用力呼气。', '颈椎或胸椎间盘突出急性期禁用。\n脊柱后凸患者需咨询专家调整动作幅度。\n近期腹部手术后未经医疗许可严禁进行。', '用双臂牵拉颈部导致紧张。\n腰部离地，转而调用髋屈肌参与。\n动作过快，浪费了离心收缩的训练价值。'),
('crunch', 'ja', 'クランチ', '腹部クランチは、腹壁前部を分離して鍛えるためのベンチマークとなる運動です。胸椎のセグメント化した屈曲に焦点を当てることで、股関節屈筋の関与を最小限に抑えながら腹直筋を効率的に鍛えます。', '腹直筋の筋力と持久力を向上させる。\n胸椎の神経筋制御を最適化する。\n体幹を通じた力伝達の効率を高める。\n外部負荷なしで高精度のトレーニングが可能。', '仰向けになり、膝を90度に曲げ、足を床につけます。\n両手を優しく後頭部に添えます（指は組まない）。\n胸椎をコントロールしながら曲げ、肩甲骨だけを床から浮かします。\n腹筋の緊張を保ちながら、ゆっくりと元の位置に戻します。', '上半身を持ち上げるのではなく、胸骨を恥骨に近づけるイメージで。\n頸部を保護するため、顎と胸の距離を一定に保つ。\n最大収縮時に力強く息を吐き出す。', '頸椎または胸椎の椎間盤ヘルニア急性期は避ける。\n脊柱後弯がある場合は、専門家と相談して可動域を調整する。\n最近の腹部手術後は医師の許可なく行わない。', '腕を使って首を引っ張り、不要な緊張を強いる。\n腰部を床から離し、股関節屈筋に負荷を逃がす。\n動作が速すぎて、エキセントリック（戻し）のフェーズを無駄にする。'),
('crunch', 'ko', '크런치', '크런치는 복벽 전면을 분리하여 자극하는 핵심 운동입니다. 흉추의 분절적 굴곡을 강조함으로써 장요근의 개입을 최소화하고 복직근을 고립시켜 코어 모터 컨트롤을 향상시킵니다.', '복직근의 근력 및 지구력 강화.\n흉추의 신경근 조절 능력 최적화.\n몸통을 통한 힘 전달 효율 향상.\n외부 저항 없이 고정밀 훈련 가능.', '바닥에 누워 무릎을 90도로 굽히고 발을 지면에 둡니다.\n손을 목 뒤에 가볍게 대고 손가락을 꼬지 않습니다.\n흉추를 통제하며 굴곡시켜 견갑골만 바닥에서 뗍니다.\n복부의 긴장을 유지하며 천천히 제자리로 돌아옵니다.', '상체 전체를 올리는 것이 아니라 흉골을 치골 쪽으로 당긴다는 느낌으로 수행하세요.\n경추 보호를 위해 턱과 가슴 사이 간격을 유지하세요.\n최대 수축 지점에서 강하게 호흡을 뱉으세요.', '경추 또는 흉추 디스크 급성기에는 금지합니다.\n척추 후만증이 있는 경우 전문가와 상의하여 가동 범위를 조절하세요.\n최근 복부 수술 이력이 있다면 의료진의 허가 없이 하지 마세요.', '손으로 목을 잡아당겨 불필요한 긴장을 유발하는 행위.\n허리를 바닥에서 떼어 장요근을 사용하는 것.\n동작 속도가 너무 빨라 신장성 수축의 이점을 잃는 것.'),
('crunch', 'ar', 'تمرين البطن (كرنش)', 'تمرين كرانش البطن هو التمرين المعياري لعزل جدار البطن الأمامي. من خلال التركيز على الثني المجزأ للعمود الفقري الصدري، فإنه يسمح بتشغيل عضلة البطن المستقيمة مع أقل تدخل لمثنيات الورك، مما يجعله حركة أساسية للتحكم الحركي بالجذع.', 'زيادة قوة وتحمل عضلة البطن المستقيمة.\nتحسين التحكم العصبي العضلي في العمود الفقري الصدري.\nتحسين كفاءة نقل القوة عبر الجذع.\nيتيح تدريباً عالي الدقة دون الحاجة لأوزان خارجية.', 'استلقِ على ظهرك مع ثني الركبتين بزاوية 90 درجة والقدمين على الأرض.\nضع يديك برفق خلف الرقبة دون تشبيك الأصابع.\nقم بثني العمود الفقري الصدري بشكل مسيطر عليه، وارفع لوحي الكتف فقط عن الأرض.\nانزل ببطء مع الحفاظ على شد عضلات البطن طوال الوقت.', 'تخيل أنك تقرب عظم القص نحو عظم العانة بدلاً من رفع الجذع بالكامل.\nحافظ على مسافة ثابتة بين الذقن والصدر لحماية الرقبة.\nأخرج الزفير بقوة عند نقطة الانقباض القصوى.', 'تجنب التمرين في مراحل الانزلاق الغضروفي العنقي أو الصدري الحادة.\nيجب على الأشخاص الذين يعانون من تحدب الظهر استشارة متخصص لتعديل مدى الحركة.\nلا تقم بالتمرين بعد عمليات جراحية حديثة في البطن دون إذن طبي.', 'استخدام الذراعين لسحب الرقبة، مما يسبب توتراً غير ضروري.\nرفع منطقة أسفل الظهر عن الأرض، مما يشغل مثنيات الورك ويقلل تركيز البطن.\nأداء الحركة بسرعة كبيرة، مما يضيع فوائد مرحلة الإطالة العضلية.'),
('crunch', 'hi', 'क्रंच', 'क्रंच व्यायाम पेट की दीवार को अलग करने के लिए एक मानक है। थोरैसिक रीढ़ के खंडित मोड़ (segmental flexion) पर ध्यान केंद्रित करके, यह कूल्हे के फ्लेक्सर्स के न्यूनतम हस्तक्षेप के साथ रेक्टस एब्डोमिनिस को काम करने की अनुमति देता है।', 'रेक्टस एब्डोमिनिस की ताकत और सहनशक्ति बढ़ाता है।\nथोरैसिक रीढ़ के न्यूरोमस्कुलर नियंत्रण को अनुकूलित करता है।\nधड़ के माध्यम से बल हस्तांतरण दक्षता में सुधार करता है।\nबाहरी प्रतिरोध के बिना उच्च-सटीक प्रशिक्षण की अनुमति देता है।', 'जमीन पर लेट जाएं, घुटने 90 डिग्री पर मुड़े हुए और पैर जमीन पर टिके हों।\nहाथों को गर्दन के पीछे हल्के से रखें, उंगलियों को आपस में न फंसाएं।\nथोरैसिक रीढ़ को नियंत्रित तरीके से मोड़ें, केवल स्कैपुला (कंधे की हड्डियों) को जमीन से उठाएं।\nधीमी गति से नीचे आएं, पूरे समय पेट में तनाव बनाए रखें।', 'धड़ को ऊपर उठाने के बजाय स्टर्नम को प्यूबिस के करीब लाने की कल्पना करें।\nगर्दन की सुरक्षा के लिए ठुड्डी और छाती के बीच एक निश्चित दूरी बनाए रखें।\nअधिकतम संकुचन के बिंदु पर बलपूर्वक सांस बाहर निकालें।', 'गर्भाशय ग्रीवा या थोरैसिक डिस्क हर्नियेशन के तीव्र चरणों के दौरान न करें।\nहाइपरकाइफोसिस वाले लोगों को गति की सीमा समायोजित करने के लिए विशेषज्ञ से परामर्श करना चाहिए।\nहालिया पेट की सर्जरी के बाद बिना चिकित्सा अनुमति के न करें।', 'हाथों का उपयोग करके गर्दन खींचना, जिससे अनावश्यक तनाव पैदा होता है।\nपीठ के निचले हिस्से को जमीन से उठाना, जो कूल्हे के फ्लेक्सर्स को सक्रिय करता है।\nबहुत तेज गति से व्यायाम करना, जिससे व्यायाम का प्रभाव कम हो जाता है।'),
('crunch', 'ru', 'Скручивания', 'Классические скручивания — это эталонное упражнение для изоляции передней брюшной стенки. Фокусируясь на сегментарном сгибании грудного отдела позвоночника, оно позволяет проработать прямую мышцу живота с минимальным вовлечением сгибателей бедра.', 'Увеличивает силу и выносливость прямой мышцы живота.\nОптимизирует нервно-мышечный контроль грудного отдела позвоночника.\nПовышает эффективность передачи силы через корпус.\nПозволяет проводить высокоточную тренировку без отягощений.', 'Лягте на спину, согните колени под углом 90 градусов, стопы на полу.\nПоложите руки за голову, не сцепляя пальцы.\nВыполните контролируемое сгибание грудного отдела, отрывая от пола только лопатки.\nМедленно опуститесь, сохраняя постоянное напряжение в прессе.', 'Представьте, что вы тянете грудину к лобку, а не просто поднимаете корпус.\nДержите расстояние между подбородком и грудью для защиты шеи.\nСделайте резкий выдох в точке пикового сокращения.', 'Избегайте при острой грыже шейного или грудного отдела позвоночника.\nПри гиперкифозе проконсультируйтесь со специалистом для настройки амплитуды.\nНе выполнять после недавних операций на брюшной полости без разрешения врача.', 'Использование рук как рычага для тяги шеи, вызывая перенапряжение.\nОтрыв поясницы от пола, что переключает нагрузку на сгибатели бедра.\nСлишком быстрое выполнение, лишающее упражнение его эффективности.'),
('crunch', 'nl', 'Crunch', 'De abdominale crunch is de standaard voor het isoleren van de voorste buikwand. Door te focussen op de gesegmenteerde flexie van de thoracale wervelkolom, wordt de rechte buikspier geactiveerd met minimale interventie van de heupbuigers.', 'Vergroot kracht en uithoudingsvermogen van de rechte buikspier.\nOptimaliseert neuromusculaire controle van de thoracale wervelkolom.\nVerbetert de efficiëntie van krachtoverdracht door de romp.\nMaakt uiterst nauwkeurige training mogelijk zonder externe weerstand.', 'Ga op je rug liggen met knieën in een hoek van 90 graden en voeten op de grond.\nPlaats je handen lichtjes achter je nek zonder de vingers te verstrengelen.\nVoer een gecontroleerde flexie van de thoracale wervelkolom uit en til alleen de schouderbladen op.\nDaal langzaam en behoud constant spanning op de buikspieren.', 'Visualiseer dat je het borstbeen naar het schaambeen brengt in plaats van de hele romp op te tillen.\nHoud een constante afstand tussen kin en borst om de nek te beschermen.\nAdem krachtig uit op het punt van maximale contractie.', 'Vermijden tijdens acute fasen van cervicale of thoracale hernia''s.\nMensen met hyperkyfose moeten een specialist raadplegen om het bewegingsbereik aan te passen.\nNiet uitvoeren na recente buikoperaties zonder medische toestemming.', 'De handen gebruiken als hefboom om aan de nek te trekken, wat spanning veroorzaakt.\nDe onderrug optillen, waardoor de heupbuigers worden geactiveerd.\nDe beweging te snel uitvoeren, waardoor de effectiviteit verloren gaat.'),
('crunch', 'sv', 'Crunch', 'Abdominella crunches är benchmark-övningen för att isolera den främre bukväggen. Genom att fokusera på segmentell flexion av bröstryggen aktiveras raka bukmusklerna med minimal inblandning av höftböjarna.', 'Ökar styrka och uthållighet i raka bukmusklerna.\nOptimerar neuromuskulär kontroll av bröstryggen.\nFörbättrar effektiviteten i kraftöverföring genom bålen.\nTillåter högprecisions-träning utan extern belastning.', 'Ligg på rygg med knäna böjda i 90 grader och fötterna på golvet.\nPlacera händerna lätt bakom nacken utan att fläta samman fingrarna.\nUtför en kontrollerad flexion av bröstryggen, lyft endast skulderbladen från golvet.\nSänk långsamt och håll konstant spänning i magen.', 'Visualisera att du för bröstbenet mot blygdbenet istället för att lyfta hela överkroppen.\nHåll ett konstant avstånd mellan hakan och bröstet för att skydda nacken.\nAndas ut kraftfullt vid punkten för maximal kontraktion.', 'Undvik vid akuta faser av diskbråck i nacke eller bröstrygg.\nPersoner med hyperkyfos bör rådfråga expertis för att justera rörelseomfånget.\nUtför ej efter nyligen utförda bukoperationer utan medicinskt godkännande.', 'Använda armarna som hävstång för att dra i nacken, vilket skapar onödig spänning.\nLyfta ländryggen från golvet, vilket engagerar höftböjarna.\nUtföra rörelsen för snabbt, vilket minskar effektiviteten.'),
('crunch', 'pl', 'Crunch', 'Crunch abdominalny to wzorcowe ćwiczenie izolujące przednią ścianę brzucha. Skupienie na segmentacyjnym zgięciu kręgosłupa piersiowego pozwala zaangażować mięsień prosty brzucha przy minimalnym udziale zginaczy bioder.', 'Zwiększa siłę i wytrzymałość mięśnia prostego brzucha.\nOptymalizuje kontrolę nerwowo-mięśniową kręgosłupa piersiowego.\nPoprawia efektywność przenoszenia siły przez tułów.\nUmożliwia trening o wysokiej precyzji bez zewnętrznego oporu.', 'Połóż się na plecach z kolanami ugiętymi pod kątem 90 stopni i stopami na podłożu.\nUmieść dłonie delikatnie za karkiem bez splatania palców.\nWykonaj kontrolowane zgięcie kręgosłupa piersiowego, odrywając tylko łopatki od podłoża.\nSchodź powoli w dół, utrzymując stałe napięcie brzucha.', 'Wyobraź sobie, że zbliżasz mostek do kości łonowej, zamiast unosić cały tułów.\nUtrzymuj stały odstęp między brodą a klatką piersiową, aby chronić szyję.\nWykonaj mocny wydech w punkcie maksymalnego napięcia.', 'Unikaj w fazach ostrych przepukliny dysku szyjnego lub piersiowego.\nOsoby z nadmierną kifozą powinny skonsultować się ze specjalistą w celu dostosowania zakresu ruchu.\nNie wykonuj po niedawnych operacjach brzusznych bez zgody lekarza.', 'Używanie rąk jako dźwigni do ciągnięcia za kark, powodujące napięcia.\nOdrywanie odcinka lędźwiowego, co angażuje zginacze bioder.\nZbyt szybkie wykonywanie ruchu, tracące korzyści treningowe.'),
('crunch', 'id', 'Crunch', 'Crunch perut adalah latihan standar untuk mengisolasi dinding perut anterior. Dengan menekankan fleksi tersegmentasi dari tulang belakang toraks, ini memungkinkan aktivasi rektus abdominis dengan intervensi minimal dari fleksor pinggul.', 'Meningkatkan kekuatan dan daya tahan rektus abdominis.\nMengoptimalkan kontrol neuromuskular dari tulang belakang toraks.\nMeningkatkan efisiensi transfer kekuatan melalui batang tubuh.\nMemungkinkan pelatihan presisi tinggi tanpa resistensi eksternal.', 'Berbaring telentang dengan lutut ditekuk 90 derajat dan kaki di lantai.\nLetakkan tangan dengan ringan di belakang leher tanpa menjalin jari.\nLakukan fleksi terkontrol pada tulang belakang toraks, hanya mengangkat tulang belikat dari lantai.\nTurun perlahan sambil menjaga ketegangan perut tetap konstan.', 'Visualisasikan membawa tulang dada ke arah tulang kemaluan daripada mengangkat seluruh batang tubuh.\nJaga jarak konstan antara dagu dan dada untuk melindungi leher.\nBuang napas dengan kuat pada titik kontraksi maksimal.', 'Hindari pada fase akut hernia diskus servikal atau toraks.\nOrang dengan hiperkifosis harus berkonsultasi dengan spesialis untuk menyesuaikan rentang gerak.\nJangan melakukan setelah operasi perut baru-baru ini tanpa izin medis.', 'Menggunakan tangan sebagai pengungkit untuk menarik leher, menyebabkan ketegangan.\nMengangkat daerah lumbal, yang melibatkan fleksor pinggul.\nMelakukan gerakan terlalu cepat, mengurangi efektivitas latihan.'),
('crunch', 'bn', 'ক্রাঞ্চ', 'পেটের ক্রাঞ্চ হলো পেটের সামনের দেয়ালকে আলাদা করার জন্য স্ট্যান্ডার্ড ব্যায়াম। থোরাসিক মেরুদণ্ডের সেগমেন্টাল ফ্লেক্সশনের ওপর জোর দেওয়ার মাধ্যমে এটি হিপ ফ্লেক্সরদের হস্তক্ষেপ ছাড়াই রেকটাস অ্যাবডোমিনিসকে সক্রিয় করে।', 'রেকটাস অ্যাবডোমিনিসের শক্তি এবং সহনশীলতা বাড়ায়।\nথোরাসিক মেরুদণ্ডের নিউরোমাসকুলার নিয়ন্ত্রণ অপ্টিমাইজ করে।\nশরীরের মাঝখান দিয়ে শক্তি স্থানান্তরের দক্ষতা উন্নত করে।\nবাইরের বাধা ছাড়াই উচ্চ-নির্ভুল প্রশিক্ষণের অনুমতি দেয়।', '৯০ ডিগ্রি কোণে হাঁটু ভাঁজ করে এবং মেঝেতে পা রেখে চিত হয়ে শুয়ে পড়ুন।\nআঙুলগুলো না জড়িয়ে ঘাড়ের পেছনে হাত হালকাভাবে রাখুন।\nথোরাসিক মেরুদণ্ড নিয়ন্ত্রিতভাবে বাঁকান, শুধুমাত্র কাঁধের হাড় মেঝে থেকে তুলুন।\nপেটে ধ্রুবক উত্তেজনা বজায় রেখে ধীরে ধীরে নিচে নামুন।', 'পুরো শরীর তোলার পরিবর্তে স্টারনাম (বুকের হাড়) কে পিউবিসের দিকে আনার কল্পনা করুন।\nঘাড় রক্ষা করতে চিবুক এবং বুকের মধ্যে একটি নির্দিষ্ট দূরত্ব রাখুন।\nসর্বোচ্চ সংকোচনের বিন্দুতে শক্তিশালী শ্বাস ছাড়ুন।', 'ঘাড় বা থোরাসিক ডিস্ক হার্নিয়ার তীব্র পর্যায় এড়িয়ে চলুন।\nহাইপারকিফোসিসযুক্ত ব্যক্তিদের গতির পরিসীমা সামঞ্জস্য করার জন্য বিশেষজ্ঞের পরামর্শ নেওয়া উচিত।\nপেটের সাম্প্রতিক অস্ত্রোপচারের পর ডাক্তারের অনুমতি ছাড়া করবেন না।', 'ঘাড় টানার জন্য হাতকে লিভার হিসেবে ব্যবহার করা, যা ঘাড়ে টান সৃষ্টি করে।\nকোমর মেঝে থেকে তোলা, যা হিপ ফ্লেক্সরদের সক্রিয় করে।\nখুব দ্রুত নড়াচড়া করা, যা ব্যায়ামের কার্যকারিতা কমিয়ে দেয়।'),
('crunch', 'vi', 'Crunch', 'Crunch bung la bai tap tieu chuan de co lap thanh bung truoc. Bang cach nhan manh su uon cong phan doan cua cot song nguc, no cho phep tac dong vao co bung thang voi su can thiep toi thieu cua co gap hong.', 'Tang cuong suc manh va do ben cua co bung thang.\nToi uu hoa kiem soat than kinh co cua cot song nguc.\nCai thien hieu qua truyen luc qua than minh.\nCho phep dao tao do chinh xac cao ma khong can suc can ben ngoai.', 'Nam ngua voi dau goi uon cong 90 do va ban chan dat tren san.\nDat tay nhe nhang sau gay ma khong can dan ngon tay.\nThuc hien su uon cong co kiem soat cua cot song nguc, chi nang xuong vai khoi san.\nHa xuong cham rai, duy tri cang thang bung lien tuc.', 'Hinh dung viec mang xuong uc ve phia xuong mu thay vi nang toan bo than minh.\nGiữ khoang cach nhat dinh giua cam va nguc de bao ve co.\nTho ra manh me tai diem co thac toi da.', 'Tranh trong cac giai doan cap tinh cua thoat vi dia dem co hoac nguc.\nNguoi bi go lung nen tham khao y kien chuyen gia de dieu chinh bien do chuyen dong.\nKhong thuc hien sau khi phau thuat bung gan day ma khong co su cho phep cua y te.', 'Su dung tay nhu don bay de keo co, gay cang thang.\nNang vung that lung khoi san, kich hoat co gap hong.\nThuc hien chuyen dong qua nhanh, lam giam hieu qua bai tap.'),
('crunch', 'fa', 'کرانچ', 'کرانچ شکم تمرین استاندارد برای جداسازی دیواره شکمی قدامی است. با تاکید بر خم شدن بخش‌بندی‌شده ستون فقرات سینه‌ای، این تمرین امکان درگیر کردن عضله راست شکم را با حداقل دخالت فلکسورهای لگن فراهم می‌کند.', 'افزایش قدرت و استقامت عضله راست شکم.\nبهینه‌سازی کنترل عصبی-عضلانی ستون فقرات سینه‌ای.\nبهبود کارایی انتقال نیرو از طریق تنه.\nامکان تمرین با دقت بالا بدون نیاز به مقاومت خارجی.', 'به پشت دراز بکشید، زانوها را ۹۰ درجه خم کرده و پاها را روی زمین قرار دهید.\nدست‌ها را به آرامی پشت گردن قرار دهید بدون اینکه انگشتان را در هم گره کنید.\nستون فقرات سینه‌ای را به صورت کنترل‌شده خم کرده و فقط استخوان کتف را از زمین بلند کنید.\nبه آرامی پایین بیایید و تنش شکمی را در طول مسیر حفظ کنید.', 'تصور کنید استخوان جناغ را به سمت استخوان عانه می‌کشید به جای اینکه کل تنه را بلند کنید.\nفاصله ثابتی بین چانه و سینه حفظ کنید تا گردن محافظت شود.\nدر نقطه اوج انقباض، بازدم محکم انجام دهید.', 'در مراحل حاد فتق دیسک گردنی یا سینه‌ای خودداری کنید.\nافراد دارای گوژپشتی باید برای تنظیم دامنه حرکت با متخصص مشورت کنند.\nپس از جراحی‌های اخیر شکم بدون اجازه پزشکی انجام ندهید.', 'استفاده از دست‌ها به عنوان اهرم برای کشیدن گردن که باعث فشار می‌شود.\nبلند کردن ناحیه کمر از زمین که فلکسورهای لگن را درگیر می‌کند.\nانجام سریع حرکت که باعث کاهش اثربخشی تمرین می‌شود.');